function FontLoader() {
  useEffect(() => {
    const l = document.createElement("link");
    l.href = "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400&family=Playfair+Display:wght@400;500;700;900&family=Josefin+Sans:wght@300;400;600&display=swap";
    l.rel = "stylesheet";
    document.head.appendChild(l);
  }, []);
  return null;
}

// ── Glitter cursor ─────────────────────────────────────────────────────────────
function GlitterCursor() {
  const [pts, setPts] = useState([]);
  useEffect(() => {
    let id = 0;
    const onMove = (e) => {
      const n = Array.from({ length: 3 }, () => ({
        id: id++, x: e.clientX, y: e.clientY,
        dx: (Math.random()-0.5)*24, dy: (Math.random()-0.5)*24,
        size: Math.random()*5+2, op: 1,
        hue: Math.random()*35+20,
      }));
      setPts(p => [...p.slice(-36), ...n]);
    };
    window.addEventListener("mousemove", onMove);
    return () => window.removeEventListener("mousemove", onMove);
  }, []);
  useEffect(() => {
    const iv = setInterval(() => {
      setPts(p => p.map(pp => ({...pp, op: pp.op-0.08, x: pp.x+pp.dx*0.12, y: pp.y+pp.dy*0.12})).filter(pp => pp.op > 0));
    }, 40);
    return () => clearInterval(iv);
  }, []);
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:9999}}>
      {pts.map(p => (
        <div key={p.id} style={{
          position:"fixed", left:p.x-p.size/2, top:p.y-p.size/2,
          width:p.size, height:p.size, borderRadius:"50%",
          background:`hsla(${p.hue},55%,72%,${p.op})`,
          boxShadow:`0 0 ${p.size*2}px hsla(${p.hue},80%,88%,${p.op*0.7})`,
          pointerEvents:"none", transform:`scale(${p.op})`,
        }}/>
      ))}
    </div>
  );
}

// ── Typewriter ──────────────────────────────────────────────────────────────────
function Typewriter({ lines }) {
  const [li, setLi] = useState(0);
  const [ci, setCi] = useState(0);
  const [done, setDone] = useState([]);
  useEffect(() => {
    if (li >= lines.length) return;
    if (ci < lines[li].length) {
      const t = setTimeout(() => setCi(c => c+1), 48);
      return () => clearTimeout(t);
    }
    const t = setTimeout(() => { setDone(d => [...d, lines[li]]); setLi(l => l+1); setCi(0); }, 420);
    return () => clearTimeout(t);
  }, [li, ci, lines]);
  const cur = li < lines.length ? lines[li].slice(0, ci) : null;
  const styles = [
    {fontFamily:"Josefin Sans,sans-serif",fontSize:"0.78rem",letterSpacing:"0.22em",textTransform:"uppercase",color:C.accent,fontWeight:600},
    {fontFamily:"Playfair Display,serif",fontSize:"1.3rem",fontWeight:700,color:C.dark,letterSpacing:"-0.01em"},
    {fontFamily:"Josefin Sans,sans-serif",fontSize:"0.78rem",letterSpacing:"0.18em",textTransform:"uppercase",color:C.brown,fontWeight:600,marginTop:"0.15rem"},
    {fontFamily:"Josefin Sans,sans-serif",fontSize:"0.78rem",letterSpacing:"0.18em",textTransform:"uppercase",color:C.muted,fontWeight:400,marginTop:"0.15rem"},
  ];
  return (
    <div style={{minHeight:"130px",marginBottom:"1rem"}}>
      {done.map((line,i) => <p key={i} style={{...styles[i],margin:"0 0 0.2rem"}}>{line}</p>)}
      {cur !== null && (
        <p style={{...styles[done.length],margin:"0 0 0.2rem"}}>
          {cur}<span style={{animation:"blink 0.8s steps(1) infinite"}}>|</span>
        </p>
      )}
    </div>
  );
}

